//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Section structure: sectPr placement, body-final vs in-paragraph,
//! sectPrChange".
//!
//! Each `#[test]` encodes a single declarative TestSpec mined from ECMA-376 /
//! ISO 29500 / MS-OI29500. A FAILING assertion here is NOT a flaky test: it
//! encodes a real Word-compliance gap in the stemma engine (stemma diverges
//! from what Word writes / consumes per the cited section). Do not weaken an
//! assertion to make it pass — fix the engine at the source, or record the gap.
//!
//! Methodology note (see the workflow brief): stemma round-trips UNTOUCHED
//! content byte-verbatim, so `reserialize()` of an unedited document reflects
//! stemma's verbatim-preservation contract for passthrough content. The xml*
//! assertions below target either (a) "opens-clean" validity, or (b) markup the
//! serializer actively rebuilds/orders (in-paragraph non-final sectPr, whose
//! children stemma re-emits in CT_SectPr schema order). Consumption semantics
//! are asserted on the read side (accept/reject text).

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: DOCX zip plumbing (mirrors the shared spec-suite prelude) ─────

/// Build a valid minimal .docx. `body_xml` is the inner content of `<w:body>`
/// (paragraphs, tables, the final sectPr). `extra_parts` is a list of
/// `(part_path, xml)` — e.g. `("word/styles.xml", "<w:styles…/>")` — for which
/// a `[Content_Types].xml` override is added based on the part name.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Build [Content_Types].xml with overrides for document.xml + extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let content_type = if part.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if part.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            panic!("make_docx: no known content-type for extra part {part}");
        };
        let part_name = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_name}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse -> serialize -> read back `word/document.xml`. This is the text the
/// engine's serializer produced (verbatim for untouched parts, rebuilt for the
/// slots stemma actively re-emits, e.g. in-paragraph sectPr child ordering).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert `needle_a` appears before `needle_b` (the regex specs only assert
/// child ordering). `label` is the rule + §refs for a self-explanatory failure.
/// Returns nothing; panics on failure.
fn assert_ordered(xml: &str, needle_a: &str, needle_b: &str, label: &str) {
    let pos_a = xml.find(needle_a);
    let pos_b = xml.find(needle_b);
    assert!(
        pos_a.is_some(),
        "{label} — expected XML to contain {needle_a}\nXML:\n{xml}"
    );
    assert!(
        pos_b.is_some(),
        "{label} — expected XML to contain {needle_b}\nXML:\n{xml}"
    );
    assert!(
        pos_a.unwrap() < pos_b.unwrap(),
        "{label} — expected {needle_a} to appear BEFORE {needle_b} (CT_SectPr / EG_SectPrContents schema order)\nXML:\n{xml}"
    );
}

fn assert_opens_clean(bytes: &[u8], label: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{label} — expected validate() to report no errors (Word opens without repair); got ok={} issues={:#?}",
        report.ok,
        report.issues
    );
}

