#[test]
fn sectprchange_previous_sectpr_stays_nested_not_a_body_section() {
    // ECMA-376 §17.6.19, ISO 29500-1 §17.6.19, ISO 29500-1 §17.13.5.32
    let body = r#"<w:p><w:r><w:t>Body paragraph.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="0"/><w:sectPrChange w:id="7" w:author="Reviewer" w:date="2024-01-01T00:00:00Z"><w:sectPr><w:pgSz w:w="15840" w:h="12240" w:orient="landscape"/></w:sectPr></w:sectPrChange></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§17.6.19: the previous-section snapshot nested in sectPrChange is well-formed revision metadata on the single final body sectPr; Word opens it without repair only if the snapshot is not promoted to a second section.",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:sectPrChange"),
        "§17.13.5.32/§17.6.19: the sectPrChange wrapper must survive parse->serialize (the revision record is preserved, not dropped). XML:\n{xml}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Body paragraph.",
        "§17.6.19: a sectPrChange records only formatting history; accepting all revisions leaves the document text unchanged, so the snapshot's pgSz must not inject any body content."
    );
}

