#[test]
fn nonfinal_sectpr_omits_type_when_absent() {
    // ECMA-376 §17.6.22, ISO 29500-1 §17.6.22
    let body = r#"<w:p><w:pPr><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:bottom="1440" w:left="1440" w:right="1440"/></w:sectPr></w:pPr><w:r><w:t>First section.</w:t></w:r></w:p><w:p><w:r><w:t>Second section.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        !xml.contains("<w:type"),
        "nextPage is the default when type is unspecified (§17.6.22); a section parsed without a w:type must not gain a fabricated w:type on serialization. XML:\n{xml}"
    );
    assert!(
        xml.contains("<w:pgSz"),
        "The modeled page size of the non-final sectPr must still be emitted, proving the sectPr was rebuilt (not dropped) yet without injecting a type (§17.6.22). XML:\n{xml}"
    );
}

#[test]
fn nonfinal_sectpr_authored_pgsz_before_type_preserved_verbatim() {
    // CONTRACT (oracle-adjudicated, see CONFORMANCE-SWEEP-SUMMARY.md): Word
    // tolerates sectPr child-order variance on open and stemma re-zips untouched
    // sectPr markup byte-for-byte. The authored pgSz-then-type order is preserved
    // on the no-edit roundtrip; asserting the serializer reorders it (type before
    // pgSz) would be a wrong-path test-bug.
    let body = r#"<w:p><w:pPr><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:type w:val="continuous"/></w:sectPr></w:pPr><w:r><w:t>Continuous section.</w:t></w:r></w:p><w:p><w:r><w:t>Final section.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    let label = "untouched sectPr markup round-trips verbatim: authored pgSz-then-type order is preserved on the no-edit roundtrip (oracle-adjudicated; §17.6.22, §17.6.18).";
    assert!(
        xml.contains(r#"<w:type w:val="continuous"/>"#),
        "{label} — expected XML to still contain <w:type w:val=\"continuous\"/>\nXML:\n{xml}"
    );
    assert_ordered(&xml, "<w:pgSz", r#"<w:type w:val="continuous"/>"#, label);

    assert_opens_clean(
        &b,
        "Word tolerates sectPr child-order variance on open, so this round-trips schema-valid (§17.6.18).",
    );
}

