#[test]
fn nonfinal_sectpr_precedes_pprchange_in_ppr() {
    // ECMA-376 §17.6.18, ISO 29500-1 §17.6.18, ECMA-376 §17.3.1.26 (CT_PPr)
    let body = r#"<w:p><w:pPr><w:jc w:val="center"/><w:sectPr><w:type w:val="nextPage"/><w:pgSz w:w="12240" w:h="15840"/></w:sectPr><w:pPrChange w:id="7" w:author="A" w:date="2026-06-01T00:00:00Z"><w:pPr/></w:pPrChange></w:pPr><w:r><w:t>First section last paragraph.</w:t></w:r></w:p><w:p><w:r><w:t>Second section paragraph.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "Non-final sectPr inside the last paragraph's pPr, ordered before pPrChange (CT_PPr sequence), with the final sectPr as the last body child is exactly Word's storage contract, so validation must report no errors (§17.6.18, §17.3.1.26).",
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "First section last paragraph.\n\nSecond section paragraph.",
        "§17.6.18 / §17.3.1.26: a section break and a pPrChange are formatting-only; accepting changes must not add or remove visible prose, so both paragraphs' text is preserved (blocks joined by the engine's blank-line separator)."
    );
}

#[test]
fn sectprchange_nonempty_prev_props_opens_clean_text_stable() {
    // ECMA-376 §17.6.19, ISO 29500-1 §17.6.19, ISO 29500-1 §17.13.5.32
    let body = r#"<w:p><w:r><w:t>Page setup changed under track changes.</w:t></w:r></w:p><w:sectPr><w:type w:val="nextPage"/><w:pgSz w:w="15840" w:h="12240" w:orient="landscape"/><w:sectPrChange w:id="42" w:author="Reviewer" w:date="2026-06-01T00:00:00Z"><w:sectPr><w:type w:val="nextPage"/><w:pgSz w:w="12240" w:h="15840"/></w:sectPr></w:sectPrChange></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "A sectPrChange whose nested CT_SectPrBase carries type+pgSz is well-formed per §17.6.19 / §17.13.5.32, so Word opens it without repair and validation reports no errors.",
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Page setup changed under track changes.",
        "§17.6.19: sectPrChange records only page-setup formatting history, so accepting all changes keeps the new layout but does not alter visible prose."
    );

    let rejected = Document::parse(&b)
        .unwrap()
        .read_rejected()
        .unwrap()
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Page setup changed under track changes.",
        "§17.6.19: rejecting restores the previous page geometry from the snapshot but, being formatting-only, must not change visible prose either."
    );
}

