#[test]
fn sectprchange_is_last_child_of_sectpr_ct_sectpr_sequence() {
    // ECMA-376 §17.6.19, ISO 29500-1 §17.13.5.32, ECMA-376 Annex A CT_SectPr
    let body = r#"<w:p><w:r><w:t>Ordered section.</w:t></w:r></w:p><w:sectPr><w:type w:val="nextPage"/><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="0"/><w:sectPrChange w:id="3" w:author="A" w:date="2024-01-01T00:00:00Z"><w:sectPr/></w:sectPrChange></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "Annex A CT_SectPr: with sectPrChange as the last child after type/pgSz/pgMar, the child sequence matches the schema; Word opens it without repair (§17.6.19 / §17.13.5.32).",
    );

    let xml = reserialize(&b);
    // Regex `<w:pgMar[^>]*/>\s*<w:sectPrChange` -> pgMar (last content child)
    // ordered before sectPrChange (the final CT_SectPr child).
    assert_ordered(
        &xml,
        "<w:pgMar",
        "<w:sectPrChange",
        "§17.6.19 / Annex A: sectPrChange must follow the section-content children (here pgMar is the last content child); the serializer must emit sectPrChange after them, not before.",
    );
}
